text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표 시점은 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["계약 자체가 잘못된 경우에만 스크립트를 검토한다."]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "result": "거절됨",
        "reason": "최종 결정은 불일치 발생 시 패키지 설정을 먼저 확인하는 것이다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정이 아님"
      },
      {
        "goal": "목요일까지 README 설치 절차 검토",
        "status": "가능하면 진행할 항목이나 담당자가 지정되지 않음"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토 담당자",
        "status": "미정"
      },
      {
        "topic": "최종 릴리스 승인 권한자",
        "status": "미정"
      },
      {
        "topic": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 여부",
        "status": "미정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정됨",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정됨",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정됨",
      "source_certainty": "담당자와 순서는 명시됨, 정확한 마감은 명시되지 않음"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능하면",
      "status": "미확정",
      "source_certainty": "검토 필요성은 언급됨, 담당자는 지정되지 않음"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과를 확인한다.",
      "스모크 실패 시 Doyun의 action_items.md 실패 트리아지 노트를 확인한다.",
      "스모크 결과 게시 후 Hara가 tarball 경로를 확인했는지 확인한다.",
      "README 설치 절차 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객 이름",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "담당자가 지정되지 않은 항목은 null 또는 미정으로 표시한다.",
    "deadline": "정확한 마감이 없는 항목은 임의로 날짜나 시간을 만들지 않는다."
  }
}
